import { LightningElement } from 'lwc';
import EditPanel from './demo';
export default class EditExample extends LightningElement {
    value = 'Sample Text';
    isEditOpen = false;
    async handleOpenEdit() {
        const button = this.template.querySelector('button');
        this.isEditOpen = true;
        const result = await EditPanel.open({
            source: button,
            position: 'bottom span-left',
            popover: 'manual',
            initialValue: this.value,
            enableFocusTrap: true,
            offsetBlock: 10
        });
        this.isEditOpen = false;
        if (result) {
            this.value = result;
        }
    }
}
